  1	import * as React from 'react';
  2	import { useParams } from 'react-router-dom';
  3	import Helmet from 'react-helmet';
  4	import { useTranslation } from 'react-i18next';
  5	import {
  6	  Page,
  7	  PageSection,
  8	  Title,
  9	  Card,
 10	  CardTitle,
 11	  CardBody,
 12	  CardExpandableContent,
 13	  CardHeader,
 14	  Flex,
 15	  FlexItem,
 16	  Text,
 17	  TextVariants,
 18	  Stack,
 19	  StackItem,
 20	  Divider,
 21	  Dropdown,
 22	  DropdownItem,
 23	  DropdownList,
 24	  MenuToggle,
 25	  Button,
 26	  Bullseye,
 27	  EmptyState,
 28	  EmptyStateIcon,
 29	  EmptyStateBody,
 30	  Label,
 31	  Popover,
 32	  Progress,
 33	  ProgressMeasureLocation,
 34	  Tooltip,
 35	} from '@patternfly/react-core';
 36	import {
 37	  GlobeIcon,
 38	  ReplicatorIcon,
 39	  OptimizeIcon,
 40	  ExternalLinkAltIcon,
 41	  EllipsisVIcon,
 42	  LockIcon,
 43	} from '@patternfly/react-icons';
 44	import {
 45	  useActiveNamespace,
 46	  usePrometheusPoll,
 47	  PrometheusEndpoint,
 48	  K8sResourceCommon,
 49	  useK8sWatchResource,
 50	  GreenCheckCircleIcon,
 51	  YellowExclamationTriangleIcon,
 52	  TableData,
 53	} from '@openshift-console/dynamic-plugin-sdk';
 54	import './kuadrant.css';
 55	import ResourceList from './ResourceList';
 56	import { sortable } from '@patternfly/react-table';
 57	import { INTERNAL_LINKS, EXTERNAL_LINKS } from '../constants/links';
 58	import resourceGVKMapping from '../utils/latest';
 59	import { useHistory } from 'react-router-dom';
 60	import useAccessReviews from '../utils/resourceRBAC';
 61	import { getResourceNameFromKind } from '../utils/getModelFromResource';
 62	
 63	export type MenuToggleElement = HTMLDivElement | HTMLButtonElement;
 64	
 65	interface Resource {
 66	  name: string;
 67	  gvk: {
 68	    group: string;
 69	    version: string;
 70	    kind: string;
 71	  };
 72	}
 73	export const resources: Resource[] = [
 74	  { name: 'AuthPolicies', gvk: resourceGVKMapping['AuthPolicy'] },
 75	  { name: 'DNSPolicies', gvk: resourceGVKMapping['DNSPolicy'] },
 76	  { name: 'RateLimitPolicies', gvk: resourceGVKMapping['RateLimitPolicy'] },
 77	  { name: 'TLSPolicies', gvk: resourceGVKMapping['TLSPolicy'] },
 78	  { name: 'Gateways', gvk: resourceGVKMapping['Gateway'] },
 79	  { name: 'HTTPRoutes', gvk: resourceGVKMapping['HTTPRoute'] },
 80	];
 81	
 82	interface TotalRequestsByGateway {
 83	  [gatewayName: string]: {
 84	    total?: number;
 85	    errors?: number;
 86	    codes?: {
 87	      [responseCode: string]: number;
 88	    };
 89	  };
 90	}
 91	interface Gateway extends K8sResourceCommon {
 92	  status?: {
 93	    conditions?: {
 94	      type: string;
 95	      status: string;
 96	    }[];
 97	  };
 98	}
 99	
100	const KuadrantOverviewPage: React.FC = () => {
101	  const history = useHistory();
102	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
103	  const { ns } = useParams<{ ns: string }>();
104	  const [activeNamespace, setActiveNamespace] = useActiveNamespace();
105	  const [isExpanded, setIsExpanded] = React.useState(true);
106	  const [isOpen, setIsOpen] = React.useState(false);
107	  const [isCreateOpen, setIsCreateOpen] = React.useState(false);
108	  const [hideCard, setHideCard] = React.useState(
109	    sessionStorage.getItem('hideGettingStarted') === 'true',
110	  );
111	  const onToggleClick = () => {
112	    setIsCreateOpen(!isCreateOpen);
113	  };
114	
115	  const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
116	  const rbacResources = resources.map((res) => ({
117	    group: res.gvk.group,
118	    kind: getResourceNameFromKind(res.gvk.kind),
119	    namespace: resolvedNamespace,
120	  }));
121	  const { userRBAC, loading } = useAccessReviews(rbacResources);
122	
123	  const policies = ['AuthPolicy', 'RateLimitPolicy', 'DNSPolicy', 'TLSPolicy'];
124	
125	  const resourceRBAC = [
126	    'TLSPolicy',
127	    'DNSPolicy',
128	    'RateLimitPolicy',
129	    'AuthPolicy',
130	    'Gateway',
131	    'HTTPRoute',
132	  ].reduce(
133	    (acc, resource) => ({
134	      ...acc,
135	      [resource]: {
136	        list: userRBAC[`${getResourceNameFromKind(resource)}-list`],
137	        create: userRBAC[`${getResourceNameFromKind(resource)}-create`],
138	      },
139	    }),
140	    {} as Record<string, { list: boolean; create: boolean }>,
141	  );
142	
143	  const policyRBACNill =
144	    !resourceRBAC['AuthPolicy']['list'] &&
145	    !resourceRBAC['RateLimitPolicy']['list'] &&
146	    !resourceRBAC['DNSPolicy']['list'] &&
147	    !resourceRBAC['TLSPolicy']['list'];
148	
149	  React.useEffect(() => {
150	    if (ns && ns !== activeNamespace) {
151	      setActiveNamespace(ns);
152	    }
153	  }, [ns, activeNamespace, setActiveNamespace]);
154	
155	  const handleHideCard = () => {
156	    setHideCard(true);
157	    sessionStorage.setItem('hideGettingStarted', 'true');
158	  };
159	
160	  const onSelect = () => {
161	    setIsOpen(!isOpen);
162	  };
163	
164	  const dropdownItems = (
165	    <>
166	      <DropdownItem key="hideForSession" onClick={handleHideCard}>
167	        {t('Hide for session')}
168	      </DropdownItem>
169	    </>
170	  );
171	
172	  const headerActions = (
173	    <>
174	      <Dropdown
175	        onSelect={onSelect}
176	        toggle={(toggleRef) => (
177	          <MenuToggle
178	            ref={toggleRef}
179	            isExpanded={isOpen}
180	            onClick={() => setIsOpen(!isOpen)}
181	            variant="plain"
182	            aria-label="Card actions"
183	          >
184	            <EllipsisVIcon aria-hidden="true" />
185	          </MenuToggle>
186	        )}
187	        isOpen={isOpen}
188	        onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
189	      >
190	        <DropdownList>{dropdownItems}</DropdownList>
191	      </Dropdown>
192	    </>
193	  );
194	
195	  const columns = [
196	    {
197	      title: t('plugin__kuadrant-console-plugin~Name'),
198	      id: 'name',
199	      sort: 'metadata.name',
200	      transforms: [sortable],
201	    },
202	    {
203	      title: t('plugin__kuadrant-console-plugin~Namespace'),
204	      id: 'namespace',
205	      sort: 'metadata.namespace',
206	      transforms: [sortable],
207	    },
208	    {
209	      title: t('plugin__kuadrant-console-plugin~Status'),
210	      id: 'Status',
211	    },
212	    {
213	      title: '',
214	      id: 'kebab',
215	      props: { className: 'pf-v6-c-table__action' },
216	    },
217	  ];
218	
219	  const gatewayTrafficColumns = [
220	    {
221	      title: t('plugin__kuadrant-console-plugin~Name'),
222	      id: 'name',
223	      sort: 'metadata.name',
224	      transforms: [sortable],
225	    },
226	    {
227	      title: t('plugin__kuadrant-console-plugin~Namespace'),
228	      id: 'namespace',
229	      sort: 'metadata.namespace',
230	      transforms: [sortable],
231	    },
232	    {
233	      title: t('plugin__kuadrant-console-plugin~Status'),
234	      id: 'Status',
235	    },
236	    {
237	      title: t('Total Requests'),
238	      id: 'totalRequests',
239	      sort: 'totalRequests',
240	      transforms: [sortable],
241	    },
242	    {
243	      title: t('Successful Requests'),
244	      id: 'successfulRequests',
245	      sort: 'successfulRequests',
246	      transforms: [sortable],
247	    },
248	    {
249	      title: t('Error Rate'),
250	      id: 'errorRate',
251	      sort: 'errorRate',
252	      transforms: [sortable],
253	    },
254	    {
255	      title: t('Error Codes'),
256	      id: 'errorCodes',
257	      sort: 'errorCodes',
258	      transforms: [sortable],
259	    },
260	    {
261	      title: '',
262	      id: 'kebab',
263	      props: { className: 'pf-v6-c-table__action' },
264	    },
265	  ];
266	
267	  const handleCreateResource = (resource) => {
268	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
269	
270	    if (resource === 'Gateway') {
271	      const gateway = resourceGVKMapping['Gateway'];
272	      history.push(
273	        `/k8s/ns/${resolvedNamespace}/${gateway.group}~${gateway.version}~${gateway.kind}/~new`,
274	      );
275	    } else {
276	      const httpRoute = resourceGVKMapping['HTTPRoute'];
277	      history.push(
278	        `/k8s/ns/${resolvedNamespace}/${httpRoute.group}~${httpRoute.version}~${httpRoute.kind}/~new`,
279	      );
280	    }
281	  };
282	
283	  const onMenuSelect = (_event: React.MouseEvent<Element, MouseEvent>, policyType: string) => {
284	    const resource = resourceGVKMapping[policyType];
285	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
286	    const targetUrl = `/k8s/ns/${resolvedNamespace}/${resource.group}~${resource.version}~${resource.kind}/~new`;
287	    history.push(targetUrl);
288	    setIsOpen(false);
289	  };
290	
291	  // Prometheus queries for gateway traffic
292	  const [totalRequestsRes, totalRequestsLoaded, totalRequestsError] = usePrometheusPoll({
293	    endpoint: PrometheusEndpoint.QUERY,
294	    query:
295	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total[24h]))',
296	  });
297	  const [totalErrorsRes, totalErrorsLoaded, totalErrorsError] = usePrometheusPoll({
298	    endpoint: PrometheusEndpoint.QUERY,
299	    query:
300	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
301	  });
302	  const [totalErrorsByCodeRes, totalErrorsByCodeLoaded, totalErrorsByCodeError] = usePrometheusPoll(
303	    {
304	      endpoint: PrometheusEndpoint.QUERY,
305	      query:
306	        'sum by (response_code, source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
307	    },
308	  );
309	
310	  // Map out query reponses to more easily accessible objects based on gateway name
311	  const totalRequestsByGateway: TotalRequestsByGateway = {};
312	  const getGateway = (name: string) => {
313	    if (!totalRequestsByGateway[name]) {
314	      totalRequestsByGateway[name] = {};
315	    }
316	    return totalRequestsByGateway[name];
317	  };
318	  if (!totalRequestsError && totalRequestsLoaded) {
319	    totalRequestsRes.data.result.forEach((item) => {
320	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
321	      getGateway(gatewayName).total = parseFloat(item.value[1]);
322	    });
323	  }
324	  if (!totalErrorsError && totalErrorsLoaded) {
325	    totalErrorsRes.data.result.forEach((item) => {
326	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
327	      getGateway(gatewayName).errors = parseFloat(item.value[1]);
328	    });
329	  }
330	  if (!totalErrorsByCodeError && totalErrorsByCodeLoaded) {
331	    totalErrorsByCodeRes.data.result.forEach((item, idx) => {
332	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
333	      const gateway = getGateway(gatewayName);
334	      if (!gateway.codes) gateway.codes = {};
335	      gateway.codes[item.metric.response_code] = parseFloat(item.value[1]);
336	    });
337	  }
338	
339	  // Helper functions to pull out metric values in correct format, given a gateway object
340	  const getTotalRequests = (obj: { metadata: { namespace: string; name: string } }): number => {
341	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
342	    const total = totalRequestsByGateway[key]?.total;
343	    return Number.isFinite(total) ? Math.round(total) : 0;
344	  };
345	  const getSuccessfulRequests = (obj: {
346	    metadata: { namespace: string; name: string };
347	  }): number => {
348	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
349	    const success = totalRequestsByGateway[key]?.total - totalRequestsByGateway[key]?.errors;
350	    return Number.isFinite(success) ? Math.round(success) : 0;
351	  };
352	  const getErrorRate = (obj: { metadata: { namespace: string; name: string } }): string => {
353	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
354	    const rate = (totalRequestsByGateway[key]?.errors / totalRequestsByGateway[key]?.total) * 100;
355	    return Number.isFinite(rate) ? rate.toFixed(1) : '-';
356	  };
357	  const getErrorCodes = (obj: { metadata: { namespace: string; name: string } }): Set<string> => {
358	    const codes = new Set<string>();
359	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
360	    if (totalRequestsByGateway[key]?.codes) {
361	      Object.entries(totalRequestsByGateway[key].codes).forEach(([key, value]) => {
362	        if (key.startsWith('4') && value > 0) {
363	          codes.add('4xx');
364	        } else if (key.startsWith('5') && value > 0) {
365	          codes.add('5xx');
366	        } // Omit all other http & non http error codes to avoid confusion.
367	      });
368	    }
369	    return codes;
370	  };
371	
372	  // Metrics columns rendering
373	  interface Distribution {
374	    total: number;
375	    percent: number;
376	  }
377	  const getErrorCodeDistribution = (
378	    obj: { metadata: { namespace: string; name: string } },
379	    prefix: string,
380	  ): Array<[string, Distribution]> => {
381	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
382	    const codes = totalRequestsByGateway[key]?.codes ?? {};
383	    const filteredCodes = Object.entries(codes).filter(([code]) => code.startsWith(prefix));
384	
385	    const total = filteredCodes.reduce((sum, [, count]) => sum + count, 0);
386	
387	    const distribution: Array<[string, Distribution]> = [];
388	    filteredCodes.forEach(([code, count]) => {
389	      if (count < 1) return;
390	      distribution.push([
391	        code,
392	        {
393	          total: count,
394	          percent: total > 0 ? (count / total) * 100 : 0,
395	        },
396	      ]);
397	    });
398	
399	    // Sort codes by total after calculating percent
400	    const sortedDistribution = distribution.sort(
401	      ([, a], [, b]) => Number(b.total) - Number(a.total),
402	    );
403	
404	    return sortedDistribution;
405	  };
406	  const ErrorCodeLabel: React.FC<{
407	    obj: { metadata: { namespace: string; name: string } };
408	    codeGroup: string;
409	  }> = ({ obj, codeGroup }) => {
410	    const [isOpen, setIsOpen] = React.useState(false);
411	    const distribution = getErrorCodeDistribution(obj, codeGroup[0]);
412	    let lastCode = '';
413	    return (
414	      <Popover
415	        className="custom-rounded-popover"
416	        headerContent={`Error Code`}
417	        bodyContent={
418	          <>
419	            <Text component={TextVariants.p}>
420	              {t('Displays the distribution of error codes for request failures.')}
421	            </Text>
422	            <div className="popover-codes">
423	              {distribution.map(([code, dist]) => {
424	                lastCode = code;
425	                return (
426	                  <div key={code} style={{ marginBottom: '8px' }}>
427	                    <Progress
428	                      value={dist.percent}
429	                      title={
430	                        <Flex
431	                          justifyContent={{ default: 'justifyContentSpaceBetween' }}
432	                          alignItems={{ default: 'alignItemsCenter' }}
433	                        >
434	                          <FlexItem>
435	                            <strong>Code: {code}</strong>
436	                          </FlexItem>
437	                          <FlexItem align={{ default: 'alignRight' }}>
438	                            {dist.total.toFixed(0) === '1'
439	                              ? '1 request'
440	                              : `${dist.total.toFixed(0)} requests`}
441	                          </FlexItem>
442	                        </Flex>
443	                      }
444	                      measureLocation={ProgressMeasureLocation.outside}
445	                    />
446	                    <Divider style={{ margin: '12px 0' }} />
447	                  </div>
448	                );
449	              })}
450	            </div>
451	          </>
452	        }
453	        footerContent={
454	          <>
455	            <span>{t('Last 24h overview')}</span>
456	          </>
457	        }
458	        isVisible={isOpen}
459	        shouldClose={() => setIsOpen(false)}
460	        position="top"
461	      >
462	        <Label
463	          variant="outline"
464	          onClick={() => setIsOpen(!isOpen)}
465	          style={{
466	            marginRight: '0.5em',
467	            textDecoration: 'underline',
468	            textDecorationStyle: 'dotted',
469	          }}
470	        >
471	          &nbsp;{distribution.length === 1 ? lastCode : codeGroup}&nbsp;
472	        </Label>
473	      </Popover>
474	    );
475	  };
476	
477	  const gatewayTrafficRenders = {
478	    totalRequests: (column, obj, activeColumnIDs) => {
479	      return (
480	        <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
481	          {getTotalRequests(obj) || '-'}
482	        </TableData>
483	      );
484	    },
485	    successfulRequests: (column, obj, activeColumnIDs) => {
486	      return (
487	        <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
488	          {getSuccessfulRequests(obj) || '-'}
489	        </TableData>
490	      );
491	    },
492	    errorRate: (column, obj, activeColumnIDs) => {
493	      return (
494	        <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
495	          {getErrorRate(obj) || '-'}%
496	        </TableData>
497	      );
498	    },
499	    errorCodes: (column, obj, activeColumnIDs) => {
500	      const errorCodes = [...getErrorCodes(obj)];
501	      return (
502	        <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
503	          {errorCodes.length === 0 ? (
504	            <Label variant="outline" color="green">
505	              {t('None')}
506	            </Label>
507	          ) : (
508	            errorCodes.map((code) => {
509	              return <ErrorCodeLabel key={code} obj={obj} codeGroup={code} />;
510	            })
511	          )}
512	        </TableData>
513	      );
514	    },
515	  };
516	
517	  const gvk = { group: 'gateway.networking.k8s.io', version: 'v1', kind: 'Gateway' };
518	
519	  const [gateways] = useK8sWatchResource<Gateway[]>({
520	    groupVersionKind: gvk,
521	    isList: true,
522	  });
523	
524	  const healthyCount = React.useMemo(() => {
525	    return gateways.filter((gw) => {
526	      const conditions = gw.status?.conditions ?? [];
527	      const accepted = conditions.some((c) => c.type === 'Accepted' && c.status === 'True');
528	      const programmed = conditions.some((c) => c.type === 'Programmed' && c.status === 'True');
529	      return accepted && programmed;
530	    }).length;
531	  }, [gateways]);
532	
533	  const unhealthyCount = gateways.length - healthyCount;
534	
535	  if (loading) {
536	    return <div>{t('Loading Permissions...')}</div>;
537	  } else
538	    return (
539	      <>
540	        <Helmet>
541	          <title data-test="example-page-title">{t('Kuadrant')}</title>
542	        </Helmet>
543	        <Page>
544	          <PageSection isFilled>
545	            <Title headingLevel="h1">{t('Kuadrant')} Overview</Title>
546	            <br />
547	
548	            {!hideCard && (
549	              <Card id="expandable-card" isExpanded={isExpanded}>
550	                <CardHeader
551	                  actions={{ actions: headerActions }}
552	                  onExpand={() => setIsExpanded(!isExpanded)}
553	                  toggleButtonProps={{
554	                    'aria-label': isExpanded
555	                      ? t('Collapse Getting Started')
556	                      : t('Expand Getting Started'),
557	                  }}
558	                >
559	                  <CardTitle>{t('Getting started resources')}</CardTitle>
560	                </CardHeader>
561	                <CardExpandableContent>
562	                  <CardBody>
563	                    <Flex className="kuadrant-overview-getting-started">
564	                      <FlexItem flex={{ default: 'flex_1' }}>
565	                        <Title headingLevel="h4" className="kuadrant-dashboard-learning">
566	                          <GlobeIcon /> {t('Learning Resources')}
567	                        </Title>
568	                        <Text component={TextVariants.small}>
569	                          {t(
570	                            'Learn how to create, import and use Kuadrant policies on OpenShift with step-by-step instructions and tasks.',
571	                          )}
572	                        </Text>
573	                        <Stack hasGutter className="pf-u-mt-sm">
574	                          <StackItem>
575	                            <Text
576	                              component="a"
577	                              href={EXTERNAL_LINKS.documentation}
578	                              className="kuadrant-dashboard-resource-link"
579	                              target="_blank"
580	                            >
581	                              {t('View Documentation')} <ExternalLinkAltIcon />
582	                            </Text>
583	                          </StackItem>
584	                          <StackItem>
585	                            <Text
586	                              component="a"
587	                              href={EXTERNAL_LINKS.secureConnectProtect}
588	                              className="kuadrant-dashboard-resource-link"
589	                              target="_blank"
590	                            >
591	                              {t('Configuring and deploying Gateway policies with Kuadrant')}{' '}
592	                              <ExternalLinkAltIcon />
593	                            </Text>
594	                          </StackItem>
595	                        </Stack>
596	                      </FlexItem>
597	                      <Divider orientation={{ default: 'vertical' }} />
598	                      <FlexItem flex={{ default: 'flex_1' }}>
599	                        <Title headingLevel="h4" className="kuadrant-dashboard-feature-highlights">
600	                          <OptimizeIcon /> {t('Feature Highlights')}
601	                        </Title>
602	                        <Text component={TextVariants.small}>
603	                          {t(
604	                            'Read about the latest information and key features in the Kuadrant highlights.',
605	                          )}
606	                        </Text>
607	                        <Stack hasGutter className="pf-u-mt-md">
608	                          <StackItem>
609	                            <Text
610	                              target="_blank"
611	                              component="a"
612	                              href={EXTERNAL_LINKS.releaseNotes}
613	                              className="kuadrant-dashboard-resource-link"
614	                            >
615	                              {t('Kuadrant')} {t('Release Notes')} <ExternalLinkAltIcon />
616	                            </Text>
617	                          </StackItem>
618	                        </Stack>
619	                      </FlexItem>
620	                      <Divider orientation={{ default: 'vertical' }} />
621	                      <FlexItem flex={{ default: 'flex_1' }}>
622	                        <Title headingLevel="h4" className="kuadrant-dashboard-enhance">
623	                          <ReplicatorIcon /> {t('Enhance Your Work')}
624	                        </Title>
625	                        <Text component={TextVariants.small}>
626	                          {t(
627	                            'Ease operational complexity with API management and App Connectivity by using additional Operators and tools.',
628	                          )}
629	                        </Text>
630	                        <Stack hasGutter className="pf-u-mt-md">
631	                          <StackItem>
632	                            <Text
633	                              component="a"
634	                              href={INTERNAL_LINKS.observabilitySetup}
635	                              className="kuadrant-dashboard-resource-link"
636	                              target="_blank"
