353	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
354	    const rate = (totalRequestsByGateway[key]?.errors / totalRequestsByGateway[key]?.total) * 100;
355	    return Number.isFinite(rate) ? rate.toFixed(1) : '-';
356	  };
357	  const getErrorCodes = (obj: { metadata: { namespace: string; name: string } }): Set<string> => {
358	    const codes = new Set<string>();
359	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
360	    if (totalRequestsByGateway[key]?.codes) {
361	      Object.entries(totalRequestsByGateway[key].codes).forEach(([key, value]) => {
362	        if (key.startsWith('4') && value > 0) {
363	          codes.add('4xx');
364	        } else if (key.startsWith('5') && value > 0) {
365	          codes.add('5xx');
366	        } // Omit all other http & non http error codes to avoid confusion.
367	      });
368	    }
