375	    percent: number;
376	  }
377	  const getErrorCodeDistribution = (
378	    obj: { metadata: { namespace: string; name: string } },
379	    prefix: string,
380	  ): Array<[string, Distribution]> => {
381	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
382	    const codes = totalRequestsByGateway[key]?.codes ?? {};
383	    const filteredCodes = Object.entries(codes).filter(([code]) => code.startsWith(prefix));
384	
385	    const total = filteredCodes.reduce((sum, [, count]) => sum + count, 0);
386	
387	    const distribution: Array<[string, Distribution]> = [];
388	    filteredCodes.forEach(([code, count]) => {
389	      if (count < 1) return;
390	      distribution.push([
391	        code,
392	        {
393	          total: count,
394	          percent: total > 0 ? (count / total) * 100 : 0,
395	        },
396	      ]);
397	    });
398	
399	    // Sort codes by total after calculating percent
400	    const sortedDistribution = distribution.sort(
401	      ([, a], [, b]) => Number(b.total) - Number(a.total),
402	    );
403	
404	    return sortedDistribution;
405	  };
