137	      },
138	    }),
139	    {} as Record<string, { list: boolean; create: boolean }>,
140	  );
141	
142	  const policyRBACNill =
143	    !resourceRBAC['AuthPolicy']['list'] &&
144	    !resourceRBAC['RateLimitPolicy']['list'] &&
145	    !resourceRBAC['DNSPolicy']['list'] &&
146	    !resourceRBAC['TLSPolicy']['list'];
147	
148	  React.useEffect(() => {
149	    if (ns && ns !== activeNamespace) {
