170	
171	  const headerActions = (
172	    <>
173	      <Dropdown
174	        onSelect={onSelect}
175	        toggle={(toggleRef) => (
176	          <MenuToggle
177	            ref={toggleRef}
178	            isExpanded={isOpen}
179	            onClick={() => setIsOpen(!isOpen)}
180	            variant="plain"
181	            aria-label="Card actions"
182	          >
183	            <EllipsisVIcon aria-hidden="true" />
184	          </MenuToggle>
185	        )}
186	        isOpen={isOpen}
187	        onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
188	      >
189	        <DropdownList>{dropdownItems}</DropdownList>
190	      </Dropdown>
191	    </>
192	  );
193	
194	  const columns = [
195	    {
196	      title: t('plugin__kuadrant-console-plugin~Name'),
197	      id: 'name',
198	      sort: 'metadata.name',
199	      transforms: [sortable],
200	    },
201	    {
202	      title: t('plugin__kuadrant-console-plugin~Namespace'),
203	      id: 'namespace',
204	      sort: 'metadata.namespace',
205	      transforms: [sortable],
206	    },
207	    {
208	      title: t('plugin__kuadrant-console-plugin~Status'),
209	      id: 'Status',
210	    },
211	    {
212	      title: '',
213	      id: 'kebab',
214	      props: { className: 'pf-v6-c-table__action' },
215	    },
216	  ];
217	
218	  const gatewayTrafficColumns = [
219	    {
220	      title: t('plugin__kuadrant-console-plugin~Name'),
221	      id: 'name',
222	      sort: 'metadata.name',
223	      transforms: [sortable],
224	    },
225	    {
226	      title: t('plugin__kuadrant-console-plugin~Namespace'),
227	      id: 'namespace',
228	      sort: 'metadata.namespace',
229	      transforms: [sortable],
230	    },
231	    {
232	      title: t('plugin__kuadrant-console-plugin~Status'),
233	      id: 'Status',
234	    },
235	    {
236	      title: t('Total Requests'),
237	      id: 'totalRequests',
238	      sort: 'totalRequests',
239	      transforms: [sortable],
240	    },
241	    {
242	      title: t('Successful Requests'),
243	      id: 'successfulRequests',
244	      sort: 'successfulRequests',
245	      transforms: [sortable],
246	    },
247	    {
248	      title: t('Error Rate'),
249	      id: 'errorRate',
250	      sort: 'errorRate',
251	      transforms: [sortable],
252	    },
253	    {
254	      title: t('Error Codes'),
255	      id: 'errorCodes',
256	      sort: 'errorCodes',
257	      transforms: [sortable],
258	    },
259	    {
260	      title: '',
261	      id: 'kebab',
262	      props: { className: 'pf-v6-c-table__action' },
263	    },
264	  ];
265	
266	  const handleCreateResource = (resource) => {
267	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
268	
269	    if (resource === 'Gateway') {
270	      const gateway = resourceGVKMapping['Gateway'];
271	      history.push(
272	        `/k8s/ns/${resolvedNamespace}/${gateway.group}~${gateway.version}~${gateway.kind}/~new`,
273	      );
274	    } else {
275	      const httpRoute = resourceGVKMapping['HTTPRoute'];
276	      history.push(
277	        `/k8s/ns/${resolvedNamespace}/${httpRoute.group}~${httpRoute.version}~${httpRoute.kind}/~new`,
278	      );
279	    }
280	  };
281	
282	  const onMenuSelect = (_event: React.MouseEvent<Element, MouseEvent>, policyType: string) => {
283	    const resource = resourceGVKMapping[policyType];
284	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
285	    const targetUrl = `/k8s/ns/${resolvedNamespace}/${resource.group}~${resource.version}~${resource.kind}/~new`;
286	    history.push(targetUrl);
287	    setIsOpen(false);
288	  };
289	
290	  // Prometheus queries for gateway traffic
291	  const [totalRequestsRes, totalRequestsLoaded, totalRequestsError] = usePrometheusPoll({
292	    endpoint: PrometheusEndpoint.QUERY,
293	    query:
294	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total[24h]))',
295	  });
296	  const [totalErrorsRes, totalErrorsLoaded, totalErrorsError] = usePrometheusPoll({
297	    endpoint: PrometheusEndpoint.QUERY,
298	    query:
299	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
300	  });
301	  const [totalErrorsByCodeRes, totalErrorsByCodeLoaded, totalErrorsByCodeError] = usePrometheusPoll(
302	    {
303	      endpoint: PrometheusEndpoint.QUERY,
304	      query:
305	        'sum by (response_code, source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
306	    },
307	  );
308	
309	  // Map out query reponses to more easily accessible objects based on gateway name
310	  const totalRequestsByGateway: TotalRequestsByGateway = {};
311	  const getGateway = (name: string) => {
312	    if (!totalRequestsByGateway[name]) {
313	      totalRequestsByGateway[name] = {};
314	    }
315	    return totalRequestsByGateway[name];
316	  };
317	  if (!totalRequestsError && totalRequestsLoaded) {
318	    totalRequestsRes.data.result.forEach((item) => {
319	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
320	      getGateway(gatewayName).total = parseFloat(item.value[1]);
321	    });
322	  }
323	  if (!totalErrorsError && totalErrorsLoaded) {
324	    totalErrorsRes.data.result.forEach((item) => {
325	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
326	      getGateway(gatewayName).errors = parseFloat(item.value[1]);
327	    });
328	  }
329	  if (!totalErrorsByCodeError && totalErrorsByCodeLoaded) {
330	    totalErrorsByCodeRes.data.result.forEach((item, idx) => {
331	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
332	      const gateway = getGateway(gatewayName);
333	      if (!gateway.codes) gateway.codes = {};
334	      gateway.codes[item.metric.response_code] = parseFloat(item.value[1]);
335	    });
336	  }
337	
338	  // Helper functions to pull out metric values in correct format, given a gateway object
339	  const getTotalRequests = (obj: { metadata: { namespace: string; name: string } }): number => {
340	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
341	    const total = totalRequestsByGateway[key]?.total;
342	    return Number.isFinite(total) ? Math.round(total) : 0;
343	  };
344	  const getSuccessfulRequests = (obj: {
345	    metadata: { namespace: string; name: string };
346	  }): number => {
347	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
348	    const success = totalRequestsByGateway[key]?.total - totalRequestsByGateway[key]?.errors;
349	    return Number.isFinite(success) ? Math.round(success) : 0;
350	  };
351	  const getErrorRate = (obj: { metadata: { namespace: string; name: string } }): string => {
352	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
353	    const rate = (totalRequestsByGateway[key]?.errors / totalRequestsByGateway[key]?.total) * 100;
354	    return Number.isFinite(rate) ? rate.toFixed(1) : '-';
355	  };
356	  const getErrorCodes = (obj: { metadata: { namespace: string; name: string } }): Set<string> => {
357	    const codes = new Set<string>();
358	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
359	    if (totalRequestsByGateway[key]?.codes) {
360	      Object.entries(totalRequestsByGateway[key].codes).forEach(([key, value]) => {
361	        if (key.startsWith('4') && value > 0) {
362	          codes.add('4xx');
363	        } else if (key.startsWith('5') && value > 0) {
364	          codes.add('5xx');
365	        } // Omit all other http & non http error codes to avoid confusion.
366	      });
367	    }
368	    return codes;
369	  };
370	
371	  // Metrics columns rendering
372	  interface Distribution {
373	    total: number;
374	    percent: number;
375	  }
376	  const getErrorCodeDistribution = (
377	    obj: { metadata: { namespace: string; name: string } },
378	    prefix: string,
379	  ): Array<[string, Distribution]> => {
380	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
381	    const codes = totalRequestsByGateway[key]?.codes ?? {};
382	    const filteredCodes = Object.entries(codes).filter(([code]) => code.startsWith(prefix));
383	
384	    const total = filteredCodes.reduce((sum, [, count]) => sum + count, 0);
385	
386	    const distribution: Array<[string, Distribution]> = [];
387	    filteredCodes.forEach(([code, count]) => {
388	      if (count < 1) return;
389	      distribution.push([
390	        code,
391	        {
392	          total: count,
393	          percent: total > 0 ? (count / total) * 100 : 0,
394	        },
395	      ]);
396	    });
397	
398	    // Sort codes by total after calculating percent
399	    const sortedDistribution = distribution.sort(
400	      ([, a], [, b]) => Number(b.total) - Number(a.total),
401	    );
402	
403	    return sortedDistribution;
404	  };
405	  const ErrorCodeLabel: React.FC<{
406	    obj: { metadata: { namespace: string; name: string } };
407	    codeGroup: string;
408	  }> = ({ obj, codeGroup }) => {
409	    const [isOpen, setIsOpen] = React.useState(false);
410	    const distribution = getErrorCodeDistribution(obj, codeGroup[0]);
411	    let lastCode = '';
412	    return (
413	      <Popover
414	        className="custom-rounded-popover"
415	        headerContent={`Error Code`}
416	        bodyContent={
417	          <>
418	            <Text component={TextVariants.p}>
419	              {t('Displays the distribution of error codes for request failures.')}
420	            </Text>
421	            <div className="popover-codes">
422	              {distribution.map(([code, dist]) => {
423	                lastCode = code;
424	                return (
425	                  <div key={code} style={{ marginBottom: '8px' }}>
426	                    <Progress
427	                      value={dist.percent}
428	                      title={
429	                        <Flex
430	                          justifyContent={{ default: 'justifyContentSpaceBetween' }}
431	                          alignItems={{ default: 'alignItemsCenter' }}
432	                        >
433	                          <FlexItem>
434	                            <strong>Code: {code}</strong>
435	                          </FlexItem>
436	                          <FlexItem align={{ default: 'alignRight' }}>
437	                            {dist.total.toFixed(0) === '1'
438	                              ? '1 request'
439	                              : `${dist.total.toFixed(0)} requests`}
440	                          </FlexItem>
441	                        </Flex>
442	                      }
443	                      measureLocation={ProgressMeasureLocation.outside}
444	                    />
445	                    <Divider style={{ margin: '12px 0' }} />
446	                  </div>
447	                );
448	              })}
449	            </div>
450	          </>
451	        }
452	        footerContent={
453	          <>
454	            <span>{t('Last 24h overview')}</span>
455	          </>
456	        }
457	        isVisible={isOpen}
458	        shouldClose={() => setIsOpen(false)}
459	        position="top"
460	      >
