 38	  OptimizeIcon,
 39	  ExternalLinkAltIcon,
 40	  EllipsisVIcon,
 41	  LockIcon,
 42	} from '@patternfly/react-icons';
 43	import {
 44	  useActiveNamespace,
 45	  usePrometheusPoll,
 46	  PrometheusEndpoint,
 47	  K8sResourceCommon,
 48	  useK8sWatchResource,
 49	  GreenCheckCircleIcon,
 50	  YellowExclamationTriangleIcon,
 51	  TableData,
 52	} from '@openshift-console/dynamic-plugin-sdk';
 53	import './kuadrant.css';
 54	import ResourceList from './ResourceList';
 55	import { sortable } from '@patternfly/react-table';
 56	import { INTERNAL_LINKS, EXTERNAL_LINKS } from '../constants/links';
 57	import resourceGVKMapping from '../utils/latest';
 58	import { useHistory } from 'react-router-dom';
 59	import useAccessReviews from '../utils/resourceRBAC';
 60	import { getResourceNameFromKind } from '../utils/getModelFromResource';
 61	
 62	export type MenuToggleElement = HTMLDivElement | HTMLButtonElement;
 63	
 64	interface Resource {
 65	  name: string;
 66	  gvk: {
 67	    group: string;
 68	    version: string;
 69	    kind: string;
 70	  };
 71	}
 72	export const resources: Resource[] = [
 73	  { name: 'AuthPolicies', gvk: resourceGVKMapping['AuthPolicy'] },
 74	  { name: 'DNSPolicies', gvk: resourceGVKMapping['DNSPolicy'] },
 75	  { name: 'RateLimitPolicies', gvk: resourceGVKMapping['RateLimitPolicy'] },
 76	  { name: 'TLSPolicies', gvk: resourceGVKMapping['TLSPolicy'] },
 77	  { name: 'Gateways', gvk: resourceGVKMapping['Gateway'] },
 78	  { name: 'HTTPRoutes', gvk: resourceGVKMapping['HTTPRoute'] },
 79	];
 80	
 81	interface TotalRequestsByGateway {
 82	  [gatewayName: string]: {
 83	    total?: number;
 84	    errors?: number;
 85	    codes?: {
 86	      [responseCode: string]: number;
 87	    };
 88	  };
 89	}
 90	interface Gateway extends K8sResourceCommon {
 91	  status?: {
 92	    conditions?: {
 93	      type: string;
 94	      status: string;
 95	    }[];
 96	  };
 97	}
 98	
 99	const KuadrantOverviewPage: React.FC = () => {
100	  const history = useHistory();
101	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
102	  const { ns } = useParams<{ ns: string }>();
103	  const [activeNamespace, setActiveNamespace] = useActiveNamespace();
104	  const [isExpanded, setIsExpanded] = React.useState(true);
105	  const [isOpen, setIsOpen] = React.useState(false);
106	  const [isCreateOpen, setIsCreateOpen] = React.useState(false);
107	  const [hideCard, setHideCard] = React.useState(
108	    sessionStorage.getItem('hideGettingStarted') === 'true',
109	  );
110	  const onToggleClick = () => {
111	    setIsCreateOpen(!isCreateOpen);
112	  };
113	
114	  const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
115	  const rbacResources = resources.map((res) => ({
116	    group: res.gvk.group,
117	    kind: getResourceNameFromKind(res.gvk.kind),
118	    namespace: resolvedNamespace,
119	  }));
120	  const { userRBAC, loading } = useAccessReviews(rbacResources);
121	
122	  const policies = ['AuthPolicy', 'RateLimitPolicy', 'DNSPolicy', 'TLSPolicy'];
123	
124	  const resourceRBAC = [
125	    'TLSPolicy',
126	    'DNSPolicy',
127	    'RateLimitPolicy',
128	    'AuthPolicy',
129	    'Gateway',
130	    'HTTPRoute',
131	  ].reduce(
132	    (acc, resource) => ({
133	      ...acc,
134	      [resource]: {
135	        list: userRBAC[`${getResourceNameFromKind(resource)}-list`],
136	        create: userRBAC[`${getResourceNameFromKind(resource)}-create`],
137	      },
138	    }),
139	    {} as Record<string, { list: boolean; create: boolean }>,
140	  );
141	
142	  const policyRBACNill =
143	    !resourceRBAC['AuthPolicy']['list'] &&
144	    !resourceRBAC['RateLimitPolicy']['list'] &&
145	    !resourceRBAC['DNSPolicy']['list'] &&
146	    !resourceRBAC['TLSPolicy']['list'];
147	
148	  React.useEffect(() => {
149	    if (ns && ns !== activeNamespace) {
150	      setActiveNamespace(ns);
151	    }
152	  }, [ns, activeNamespace, setActiveNamespace]);
153	
154	  const handleHideCard = () => {
155	    setHideCard(true);
156	    sessionStorage.setItem('hideGettingStarted', 'true');
157	  };
158	
159	  const onSelect = () => {
160	    setIsOpen(!isOpen);
161	  };
162	
163	  const dropdownItems = (
164	    <>
165	      <DropdownItem key="hideForSession" onClick={handleHideCard}>
166	        {t('Hide for session')}
167	      </DropdownItem>
168	    </>
169	  );
170	
171	  const headerActions = (
172	    <>
173	      <Dropdown
174	        onSelect={onSelect}
175	        toggle={(toggleRef) => (
176	          <MenuToggle
177	            ref={toggleRef}
178	            isExpanded={isOpen}
179	            onClick={() => setIsOpen(!isOpen)}
180	            variant="plain"
181	            aria-label="Card actions"
182	            icon={<EllipsisVIcon aria-hidden="true" />}
183	          />
184	        )}
185	        isOpen={isOpen}
186	        onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
187	      >
188	        <DropdownList>{dropdownItems}</DropdownList>
189	      </Dropdown>
190	    </>
191	  );
192	
193	  const columns = [
194	    {
195	      title: t('plugin__kuadrant-console-plugin~Name'),
196	      id: 'name',
197	      sort: 'metadata.name',
198	      transforms: [sortable],
199	    },
200	    {
201	      title: t('plugin__kuadrant-console-plugin~Namespace'),
202	      id: 'namespace',
203	      sort: 'metadata.namespace',
204	      transforms: [sortable],
205	    },
206	    {
207	      title: t('plugin__kuadrant-console-plugin~Status'),
208	      id: 'Status',
209	    },
210	    {
211	      title: '',
212	      id: 'kebab',
213	      props: { className: 'pf-v6-c-table__action' },
214	    },
215	  ];
216	
217	  const gatewayTrafficColumns = [
218	    {
219	      title: t('plugin__kuadrant-console-plugin~Name'),
220	      id: 'name',
221	      sort: 'metadata.name',
222	      transforms: [sortable],
223	    },
224	    {
225	      title: t('plugin__kuadrant-console-plugin~Namespace'),
226	      id: 'namespace',
227	      sort: 'metadata.namespace',
228	      transforms: [sortable],
229	    },
230	    {
231	      title: t('plugin__kuadrant-console-plugin~Status'),
232	      id: 'Status',
233	    },
234	    {
235	      title: t('Total Requests'),
236	      id: 'totalRequests',
237	      sort: 'totalRequests',
238	      transforms: [sortable],
239	    },
240	    {
241	      title: t('Successful Requests'),
242	      id: 'successfulRequests',
243	      sort: 'successfulRequests',
244	      transforms: [sortable],
245	    },
246	    {
247	      title: t('Error Rate'),
248	      id: 'errorRate',
249	      sort: 'errorRate',
250	      transforms: [sortable],
251	    },
252	    {
253	      title: t('Error Codes'),
254	      id: 'errorCodes',
255	      sort: 'errorCodes',
256	      transforms: [sortable],
257	    },
258	    {
259	      title: '',
260	      id: 'kebab',
261	      props: { className: 'pf-v6-c-table__action' },
262	    },
263	  ];
264	
265	  const handleCreateResource = (resource) => {
266	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
267	
268	    if (resource === 'Gateway') {
269	      const gateway = resourceGVKMapping['Gateway'];
270	      history.push(
271	        `/k8s/ns/${resolvedNamespace}/${gateway.group}~${gateway.version}~${gateway.kind}/~new`,
272	      );
273	    } else {
274	      const httpRoute = resourceGVKMapping['HTTPRoute'];
275	      history.push(
276	        `/k8s/ns/${resolvedNamespace}/${httpRoute.group}~${httpRoute.version}~${httpRoute.kind}/~new`,
277	      );
278	    }
279	  };
280	
281	  const onMenuSelect = (_event: React.MouseEvent<Element, MouseEvent>, policyType: string) => {
282	    const resource = resourceGVKMapping[policyType];
283	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
284	    const targetUrl = `/k8s/ns/${resolvedNamespace}/${resource.group}~${resource.version}~${resource.kind}/~new`;
285	    history.push(targetUrl);
286	    setIsOpen(false);
287	  };
288	
289	  // Prometheus queries for gateway traffic
290	  const [totalRequestsRes, totalRequestsLoaded, totalRequestsError] = usePrometheusPoll({
291	    endpoint: PrometheusEndpoint.QUERY,
292	    query:
293	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total[24h]))',
294	  });
295	  const [totalErrorsRes, totalErrorsLoaded, totalErrorsError] = usePrometheusPoll({
296	    endpoint: PrometheusEndpoint.QUERY,
297	    query:
298	      'sum by (source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
299	  });
300	  const [totalErrorsByCodeRes, totalErrorsByCodeLoaded, totalErrorsByCodeError] = usePrometheusPoll(
301	    {
302	      endpoint: PrometheusEndpoint.QUERY,
303	      query:
304	        'sum by (response_code, source_workload, source_workload_namespace) (increase(istio_requests_total{response_code!~"2(.*)|3(.*)"}[24h]))',
305	    },
306	  );
307	
308	  // Map out query reponses to more easily accessible objects based on gateway name
309	  const totalRequestsByGateway: TotalRequestsByGateway = {};
310	  const getGateway = (name: string) => {
311	    if (!totalRequestsByGateway[name]) {
312	      totalRequestsByGateway[name] = {};
313	    }
314	    return totalRequestsByGateway[name];
315	  };
316	  if (!totalRequestsError && totalRequestsLoaded) {
317	    totalRequestsRes.data.result.forEach((item) => {
318	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
319	      getGateway(gatewayName).total = parseFloat(item.value[1]);
320	    });
321	  }
322	  if (!totalErrorsError && totalErrorsLoaded) {
323	    totalErrorsRes.data.result.forEach((item) => {
324	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
325	      getGateway(gatewayName).errors = parseFloat(item.value[1]);
326	    });
327	  }
328	  if (!totalErrorsByCodeError && totalErrorsByCodeLoaded) {
329	    totalErrorsByCodeRes.data.result.forEach((item, idx) => {
330	      const gatewayName = `${item.metric.source_workload_namespace}/${item.metric.source_workload}`;
331	      const gateway = getGateway(gatewayName);
332	      if (!gateway.codes) gateway.codes = {};
333	      gateway.codes[item.metric.response_code] = parseFloat(item.value[1]);
334	    });
335	  }
336	
337	  // Helper functions to pull out metric values in correct format, given a gateway object
338	  const getTotalRequests = (obj: { metadata: { namespace: string; name: string } }): number => {
339	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
340	    const total = totalRequestsByGateway[key]?.total;
341	    return Number.isFinite(total) ? Math.round(total) : 0;
342	  };
343	  const getSuccessfulRequests = (obj: {
344	    metadata: { namespace: string; name: string };
345	  }): number => {
346	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
347	    const success = totalRequestsByGateway[key]?.total - totalRequestsByGateway[key]?.errors;
348	    return Number.isFinite(success) ? Math.round(success) : 0;
349	  };
350	  const getErrorRate = (obj: { metadata: { namespace: string; name: string } }): string => {
351	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
352	    const rate = (totalRequestsByGateway[key]?.errors / totalRequestsByGateway[key]?.total) * 100;
353	    return Number.isFinite(rate) ? rate.toFixed(1) : '-';
354	  };
355	  const getErrorCodes = (obj: { metadata: { namespace: string; name: string } }): Set<string> => {
356	    const codes = new Set<string>();
357	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
358	    if (totalRequestsByGateway[key]?.codes) {
359	      Object.entries(totalRequestsByGateway[key].codes).forEach(([key, value]) => {
360	        if (key.startsWith('4') && value > 0) {
361	          codes.add('4xx');
362	        } else if (key.startsWith('5') && value > 0) {
363	          codes.add('5xx');
364	        } // Omit all other http & non http error codes to avoid confusion.
365	      });
366	    }
367	    return codes;
368	  };
369	
370	  // Metrics columns rendering
371	  interface Distribution {
372	    total: number;
373	    percent: number;
374	  }
375	  const getErrorCodeDistribution = (
376	    obj: { metadata: { namespace: string; name: string } },
377	    prefix: string,
378	  ): Array<[string, Distribution]> => {
379	    const key = `${obj.metadata.namespace}/${obj.metadata.name}-istio`;
380	    const codes = totalRequestsByGateway[key]?.codes ?? {};
381	    const filteredCodes = Object.entries(codes).filter(([code]) => code.startsWith(prefix));
382	
383	    const total = filteredCodes.reduce((sum, [, count]) => sum + count, 0);
384	
385	    const distribution: Array<[string, Distribution]> = [];
386	    filteredCodes.forEach(([code, count]) => {
387	      if (count < 1) return;
388	      distribution.push([
389	        code,
390	        {
391	          total: count,
392	          percent: total > 0 ? (count / total) * 100 : 0,
393	        },
394	      ]);
395	    });
396	
397	    // Sort codes by total after calculating percent
398	    const sortedDistribution = distribution.sort(
399	      ([, a], [, b]) => Number(b.total) - Number(a.total),
400	    );
401	
402	    return sortedDistribution;
403	  };
404	  const ErrorCodeLabel: React.FC<{
405	    obj: { metadata: { namespace: string; name: string } };
406	    codeGroup: string;
407	  }> = ({ obj, codeGroup }) => {
408	    const [isOpen, setIsOpen] = React.useState(false);
409	    const distribution = getErrorCodeDistribution(obj, codeGroup[0]);
410	    let lastCode = '';
411	    return (
412	      <Popover
413	        className="custom-rounded-popover"
414	        headerContent={`Error Code`}
415	        bodyContent={
416	          <>
417	            <Text component={TextVariants.p}>
418	              {t('Displays the distribution of error codes for request failures.')}
419	            </Text>
420	            <div className="popover-codes">
421	              {distribution.map(([code, dist]) => {
422	                lastCode = code;
423	                return (
424	                  <div key={code} style={{ marginBottom: '8px' }}>
425	                    <Progress
426	                      value={dist.percent}
427	                      title={
428	                        <Flex
429	                          justifyContent={{ default: 'justifyContentSpaceBetween' }}
